3150   // Currently, we can't handle alias masking in reverse. Reversing the alias
3151   // mask is not correct (or necessary). When combined with tail-folding the ALM
3152   // should only be reversed where the alias-mask is true.
3153   if (Stride < 0)
3154     disablePartialAliasMaskingIfEnabled();
