3156   // If the instruction is a store located in a predicated block, it will be
3157   // scalarized.
3158   if (isScalarWithPredication(I, VF))
3159     return false;
3160 
3161   // If the instruction's allocated size doesn't equal it's type size, it
3162   // requires padding and will be scalarized.
3163   auto &DL = I->getDataLayout();
3164   if (hasIrregularType(ScalarTy, DL))
3165     return false;
